// Wire-protocol types (must match ws.ts on server)

export interface Job {
  sessionId: string;
  name: string;
  issueNumber: number;
  agent: string;
  step: number;
  status: "pending" | "running" | "succeeded" | "failed" | "purged";
  startedAt: string | null;
  completedAt: string | null;
  podName: string | null;
  issueTitle: string | null;
  branchName: string | null;
  fixture?: boolean;
}

// Server → Client
export type ServerMessage =
  | { type: "jobs-snapshot"; ts: number; jobs: Job[] }
  | { type: "jobs-updated"; ts: number; jobs: Job[] }
  | { type: "log-line"; ts: number; sessionId: string; line: string }
  | { type: "verdict"; ts: number; sessionId: string; result: "PASS" | "FAIL" }
  | {
      type: "stream-end";
      ts: number;
      sessionId: string;
      reason: "completed" | "failed" | "cancelled";
    }
  | { type: "stream-error"; ts: number; sessionId: string; message: string }
  | { type: "fixture-start"; ts: number; sessionId: string }
  | { type: "pong" }
  | { type: "error"; message: string };

// Client → Server
export type ClientMessage =
  | { type: "subscribe"; sessionId: string }
  | { type: "unsubscribe"; sessionId: string }
  | { type: "set-speed"; sessionId: string; speed: number }
  | { type: "ping" };

// Parsed display-ready job
export interface DisplayJob {
  sessionId: string;
  name: string;
  issue: string;
  step: string;
  agentKey?: string | undefined;
  agentName: string;
  status: Job["status"];
  startTime: number | null;
  completionTime: number | null;
  issueTitle: string | null;
  branchName: string | null;
}

// JSONL event types
export interface ContentBlock {
  type: string;
  text?: string;
  id?: string;
  name?: string;
  input?: Record<string, unknown>;
  tool_use_id?: string;
  content?: string | ContentBlock[];
  is_error?: boolean;
}

export interface JsonEvent {
  type: string;
  subtype?: string;
  model?: string;
  cwd?: string;
  timestamp?: string;
  message?: {
    id?: string;
    role?: string;
    content?: ContentBlock[];
    usage?: { input_tokens?: number; output_tokens?: number };
  };
  [key: string]: unknown;
}
import type { Job } from "./types";

export const AGENT_NAMES: Record<string, string> = {
  firemandecko: "FiremanDecko",
  loki: "Loki",
  luna: "Luna",
  freya: "Freya",
  heimdall: "Heimdall",
};

export const AGENT_TITLES: Record<string, string> = {
  firemandecko: "Principal Engineer",
  loki: "QA Tester",
  luna: "UX Designer",
  freya: "Product Owner",
  heimdall: "Security Specialist",
};

export const AGENT_AVATARS: Record<string, string> = {
  firemandecko: "/agents/fireman-decko-dark.png",
  loki: "/agents/loki-dark.png",
  luna: "/agents/luna-dark.png",
  freya: "/agents/freya-dark.png",
  heimdall: "/agents/heimdall-dark.png",
};

export const AGENT_COLORS: Record<string, string> = {
