    60→
    61→/**
    62→ * Open a WebSocket AND register a message collector simultaneously.
    63→ * IMPORTANT: listeners must be registered before the WS opens to avoid
    64→ * missing the first message (jobs-snapshot is sent in a microtask that fires
    65→ * before the client open event propagates through Promise chains).
    66→ */
    67→function connectAndCollect(
    68→  port: number
    69→): { ws: WebSocket; nextMsg: () => Promise<string>; open: Promise<void> } {
    70→  const ws = new WebSocket(`ws://127.0.0.1:${port}/ws`);
    71→  const queue: string[] = [];
    72→  const waiters: Array<(s: string) => void> = [];
    73→
    74→  ws.on("message", (data) => {
    75→    const s = String(data);
    76→    const waiter = waiters.shift();
    77→    if (waiter) {
    78→      waiter(s);
    79→    } else {
    80→      queue.push(s);
    81→    }
    82→  });
    83→
    84→  const nextMsg = (ms = 4000) =>
    85→    new Promise<string>((resolve, reject) => {
    86→      const msg = queue.shift();
    87→      if (msg) { resolve(msg); return; }
    88→      const t = setTimeout(() => {
    89→        const idx = waiters.indexOf(resolve);
    90→        if (idx !== -1) waiters.splice(idx, 1);
    91→        reject(new Error(`WS msg timeout after ${ms}ms`));
    92→      }, ms);
    93→      waiters.push((s) => { clearTimeout(t); resolve(s); });
    94→    });
    95→
    96→  const open = new Promise<void>((resolve, reject) => {
    97→    ws.once("open", () => resolve());
    98→    ws.once("error", reject);
    99→  });
   100→
   101→  return { ws, nextMsg, open };
   102→}
   103→
   104→function waitForType<T extends { type: string }>(
   105→  nextMsg: () => Promise<string>,
   106→  type: string,
   107→  maxMessages = 5
   108→): Promise<T> {
   109→  const tryNext = async (remaining: number): Promise<T> => {
   110→    if (remaining === 0) throw new Error(`Did not find type="${type}" in ${maxMessages} messages`);
   111→    const raw = await nextMsg();
   112→    const parsed = JSON.parse(raw) as T;
   113→    if (parsed.type === type) return parsed;
   114→    return tryNext(remaining - 1);
   115→  };
   116→  return tryNext(maxMessages);
   117→}
   118→
   119→function makeJob(overrides: Partial<Job> = {}): Job {
   120→  return {
   121→    sessionId: "issue-963-step1-loki",
   122→    name: "agent-issue-963-step1-loki",
   123→    issueNumber: 963,
   124→    agent: "loki",
   125→    step: 1,
   126→    status: "pending",
   127→    startedAt: "2026-03-15T10:00:00Z",
   128→    completedAt: null,
   129→    podName: null,
   130→    ...overrides,
   131→  };
   132→}
   133→
   134→// ── Suite ─────────────────────────────────────────────────────────────────────
   135→
   136→describe("WebSocket server — job status broadcasts (issue #963)", () => {
   137→  let httpServer: ReturnType<typeof createServer>;
   138→  let port: number;
   139→
   140→  beforeEach(async () => {
   141→    capture.watchCb = null;
   142→    httpServer = createServer();
   143→    attachWebSocketServer(httpServer as Parameters<typeof attachWebSocketServer>[0]);
   144→    await new Promise<void>((resolve) => {
   145→      httpServer.listen(0, "127.0.0.1", () => resolve());
   146→    });
   147→    port = (httpServer.address() as { port: number }).port;
   148→  }, 15_000);
   149→
   150→  afterEach(async () => {
   151→    httpServer.closeAllConnections?.();
   152→    await new Promise<void>((resolve) => httpServer.close(() => resolve()));
   153→  }, 15_000);
   154→
   155→  // ── Connection handshake ─────────────────────────────────────────────────
   156→
   157→  it("sends jobs-snapshot to a newly connected client", async () => {
   158→    const { ws, nextMsg, open } = connectAndCollect(port);
   159→    await open;
   160→    try {
   161→      const msg = await waitForType<{ type: string; jobs: unknown[]; ts: number }>(nextMsg, "jobs-snapshot");
   162→      expect(msg.type).toBe("jobs-snapshot");
   163→      expect(Array.isArray(msg.jobs)).toBe(true);
   164→      expect(typeof msg.ts).toBe("number");
   165→    } finally {
   166→      ws.close();
   167→    }
   168→  });
   169→
   170→  // ── AC: pending while scheduling ─────────────────────────────────────────
   171→
   172→  it("broadcasts pending status when job is scheduling", async () => {
   173→    const { ws, nextMsg, open } = connectAndCollect(port);
   174→    await open;
   175→    await waitForType(nextMsg, "jobs-snapshot");
   176→    try {
   177→      capture.watchCb!([makeJob({ status: "pending" })]);
   178→      const msg = await waitForType<{ type: string; jobs: Job[] }>(nextMsg, "jobs-updated");
   179→      expect(msg.jobs[0]?.status).toBe("pending");
   180→    } finally {
   181→      ws.close();
   182→    }
   183→  });
   184→
   185→  // ── AC: running when pod becomes active ──────────────────────────────────
   186→
   187→  it("broadcasts running status when pod starts executing", async () => {
   188→    const { ws, nextMsg, open } = connectAndCollect(port);
   189→    await open;
   190→    await waitForType(nextMsg, "jobs-snapshot");
   191→    try {
   192→      capture.watchCb!([makeJob({ status: "running" })]);
   193→      const msg = await waitForType<{ type: string; jobs: Job[] }>(nextMsg, "jobs-updated");
   194→      expect(msg.jobs[0]?.status).toBe("running");
   195→    } finally {
   196→      ws.close();
   197→    }
   198→  });
   199→
   200→  // ── AC: succeeded on completion ───────────────────────────────────────────
   201→
   202→  it("broadcasts succeeded status when job completes", async () => {
   203→    const { ws, nextMsg, open } = connectAndCollect(port);
   204→    await open;
   205→    await waitForType(nextMsg, "jobs-snapshot");
   206→    try {
   207→      capture.watchCb!([makeJob({ status: "succeeded", completedAt: "2026-03-15T11:00:00Z" })]);
   208→      const msg = await waitForType<{ type: string; jobs: Job[] }>(nextMsg, "jobs-updated");
   209→      expect(msg.jobs[0]?.status).toBe("succeeded");
   210→      expect(msg.jobs[0]?.completedAt).toBe("2026-03-15T11:00:00Z");
   211→    } finally {
   212→      ws.close();
   213→    }
   214→  });
   215→
   216→  // ── AC: failed on error ───────────────────────────────────────────────────
   217→
   218→  it("broadcasts failed status when job fails", async () => {
   219→    const { ws, nextMsg, open } = connectAndCollect(port);
   220→    await open;
