     1→import { WebSocketServer, WebSocket } from "ws";
     2→import type { IncomingMessage, Server } from "node:http";
     3→import type { ServerType } from "@hono/node-server";
     4→import { readFileSync, existsSync, readdirSync, statSync } from "node:fs";
     5→import { resolve, dirname } from "node:path";
     6→import { fileURLToPath } from "node:url";
     7→import {
     8→  streamPodLogs,
     9→  findPodForSession,
    10→  listAgentJobs,
    11→  watchAgentJobs,
    12→  mapAgentJobToJob,
    13→} from "./k8s.js";
    14→import type { Job } from "./k8s.js";
    15→import { parseJsonlLine, detectVerdict } from "./report.js";
    16→
    17→// ── K8s error message sanitiser ─────────────────────────────────────────────
    18→
    19→/**
    20→ * Regex matching node-unreachable / kubelet-timeout patterns that appear in
    21→ * 500-class K8s errors when a node is down or the kubelet is unresponsive.
    22→ *
    23→ * Matches messages containing any of:
    24→ *   - "i/o timeout"
    25→ *   - kubelet port 10250 connection failures ("dial tcp …:10250")
    26→ *   - "node … not ready" / "node … unreachable"
    27→ *   - "context deadline exceeded"
    28→ */
    29→export const NODE_UNREACHABLE_PATTERN =
    30→  /i\/o timeout|dial tcp[^)]*:10250|node[^\n]*(?:not ready|unreachable)|context deadline exceeded/i;
    31→
    32→/** Strip RFC-1918 / link-local IP addresses to avoid leaking internal topology. */
    33→function stripInternalIPs(msg: string): string {
    34→  return msg
    35→    .replace(/\b10\.\d{1,3}\.\d{1,3}\.\d{1,3}\b/g, "<node-ip>")
    36→    .replace(/\b192\.168\.\d{1,3}\.\d{1,3}\b/g, "<node-ip>")
    37→    .replace(/\b172\.(?:1[6-9]|2\d|3[01])\.\d{1,3}\.\d{1,3}\b/g, "<node-ip>")
    38→    .replace(/\b169\.254\.\d{1,3}\.\d{1,3}\b/g, "<node-ip>");
    39→}
    40→
    41→/**
    42→ * Map raw Kubernetes API errors to clean, user-friendly messages.
    43→ *
    44→ * The @kubernetes/client-node library often throws errors whose `.message`
    45→ * contains raw HTTP details such as status lines, header dumps, and
    46→ * "Body: undefined". This function strips all of that and returns a
    47→ * single human-readable sentence safe to display in the monitor UI.
    48→ */
    49→export function friendlyK8sError(rawMessage: string, sessionId: string): string {
    50→  // Detect node-unreachable / kubelet-timeout patterns before checking status code.
    51→  // These typically arrive as 500 but deserve a more specific, actionable message.
    52→  if (NODE_UNREACHABLE_PATTERN.test(rawMessage)) {
    53→    return `Node unreachable — the Kubernetes node running session ${sessionId} is not responding (kubelet timeout). The cluster is retrying; logs will resume if the node recovers.`;
    54→  }
    55→
    56→  // Detect HTTP status code from messages like "HTTP status code 404" or "404 Not Found"
    57→  const statusMatch = /\b(4\d\d|5\d\d)\b/.exec(rawMessage);
    58→  const status = statusMatch ? parseInt(statusMatch[1]!, 10) : null;
    59→
    60→  switch (status) {
    61→    case 404:
    62→      return `Logs unavailable — the pod for session ${sessionId} has been cleaned up (job TTL expired).`;
    63→    case 403:
    64→      return `Access denied to pod logs for session ${sessionId}. Contact your cluster administrator.`;
    65→    case 401:
    66→      return `Authentication error — check cluster credentials.`;
    67→    case 500:
    68→      return `Kubernetes API server error while fetching logs for session ${sessionId}. The cluster may be experiencing issues.`;
    69→    case 503:
    70→      return `Kubernetes API unavailable — the cluster may be temporarily unreachable.`;
    71→    default:
    72→      break;
    73→  }
    74→
    75→  // Strip raw HTTP artefacts: headers, status lines, "Body: undefined", etc.
    76→  // Also redact internal IPs that may have slipped through.
    77→  const stripped = stripInternalIPs(rawMessage)
    78→    .replace(/HTTP response body:.*$/gim, "")
    79→    .replace(/HTTP status code:?\s*\d+/gi, "")
    80→    .replace(/\bBody:\s*undefined\b/gi, "")
    81→    .replace(/\bContent-Type:[^\n]*/gi, "")
    82→    .replace(/\bAuthorization:[^\n]*/gi, "")
    83→    .replace(/\n{2,}/g, " ")
    84→    .trim();
    85→
    86→  if (stripped.length > 0 && stripped.length < 300) {
    87→    return stripped;
    88→  }
    89→
    90→  return `An unexpected error occurred while streaming logs for session ${sessionId}.`;
    91→}
    92→
    93→// ── Fixture fallback for local dev (disabled in production) ─────────────────
    94→const FIXTURES_ENABLED = process.env.NODE_ENV !== "production";
    95→const __dirname = dirname(fileURLToPath(import.meta.url));
    96→const FIXTURES_DIR = resolve(__dirname, "../fixtures");
    97→
    98→function findFixture(sessionId: string): string | null {
    99→  if (!FIXTURES_ENABLED) return null;
   100→  if (!existsSync(FIXTURES_DIR)) return null;
   101→  // Match agent-<sessionId>.jsonl
   102→  const exact = resolve(FIXTURES_DIR, `agent-${sessionId}.jsonl`);
   103→  if (existsSync(exact)) return exact;
   104→  // Fuzzy: any file containing the sessionId
   105→  try {
   106→    const files = readdirSync(FIXTURES_DIR);
   107→    const match = files.find((f) => f.includes(sessionId) && f.endsWith(".jsonl"));
   108→    return match ? resolve(FIXTURES_DIR, match) : null;
   109→  } catch {
   110→    return null;
   111→  }
   112→}
   113→
   114→/** Scan fixtures dir and return Job entries for each .jsonl file found. */
   115→function listFixtureJobs(): Job[] {
   116→  if (!FIXTURES_ENABLED) return [];
   117→  if (!existsSync(FIXTURES_DIR)) return [];
   118→  try {
   119→    const files = readdirSync(FIXTURES_DIR).filter((f) => f.endsWith(".jsonl"));
   120→    return files.map((f) => {
   121→      const sessionId = f.replace(/^agent-/, "").replace(/\.jsonl$/, "");
   122→      const m = sessionId.match(/issue-(\d+)-step(\d+)-([a-z]+)/i);
   123→      const stat = statSync(resolve(FIXTURES_DIR, f));
   124→      return {
   125→        sessionId,
   126→        name: f.replace(/\.jsonl$/, ""),
   127→        issueNumber: m ? parseInt(m[1] ?? "0", 10) : 0,
   128→        agent: m ? (m[3] ?? "unknown").toLowerCase() : "unknown",
   129→        step: m ? parseInt(m[2] ?? "0", 10) : 0,
   130→        status: "succeeded" as const,
   131→        startedAt: stat.mtime.toISOString(),
   132→        completedAt: stat.mtime.toISOString(),
   133→        podName: null,
   134→        issueTitle: null,
   135→        branchName: null,
   136→        fixture: true,
   137→      };
   138→    });
   139→  } catch {
   140→    return [];
   141→  }
   142→}
   143→
   144→// ---------------------------------------------------------------------------
   145→// Wire protocol — Server → Client
   146→// ---------------------------------------------------------------------------
   147→
   148→type ServerMessage =
   149→  | { type: "jobs-snapshot"; ts: number; jobs: Job[] }
   150→  | { type: "jobs-updated"; ts: number; jobs: Job[] }
   151→  | { type: "log-line"; ts: number; sessionId: string; line: string }
   152→  | { type: "verdict"; ts: number; sessionId: string; result: "PASS" | "FAIL" }
   153→  | {
   154→      type: "stream-end";
   155→      ts: number;
   156→      sessionId: string;
   157→      reason: "completed" | "failed" | "cancelled";
   158→    }
   159→  | { type: "stream-error"; ts: number; sessionId: string; message: string }
   160→  | { type: "fixture-start"; ts: number; sessionId: string }
   161→  | { type: "pong" }
   162→  | { type: "error"; message: string };
   163→
   164→// ---------------------------------------------------------------------------
   165→// Wire protocol — Client → Server
   166→// ---------------------------------------------------------------------------
   167→
   168→type ClientMessage =
   169→  | { type: "subscribe"; sessionId: string }
   170→  | { type: "unsubscribe"; sessionId: string }
   171→  | { type: "ping" };
   172→
   173→// ---------------------------------------------------------------------------
   174→// Helpers
   175→// ---------------------------------------------------------------------------
   176→
   177→function sortJobsByStartedAtDesc(jobs: Job[]): Job[] {
   178→  return [...jobs].sort((a, b) => {
   179→    const aTime = a.startedAt ? new Date(a.startedAt).getTime() : 0;
   180→    const bTime = b.startedAt ? new Date(b.startedAt).getTime() : 0;
   181→    return bTime - aTime;
   182→  });
   183→}
   184→
   185→/** Merge fixture jobs with live K8s jobs. Live jobs take precedence by sessionId. */
   186→function mergeWithFixtures(liveJobs: Job[]): Job[] {
   187→  const fixtureJobs = listFixtureJobs();
   188→  if (fixtureJobs.length === 0) return sortJobsByStartedAtDesc(liveJobs);
   189→  const liveIds = new Set(liveJobs.map((j) => j.sessionId));
   190→  const extras = fixtureJobs.filter((f) => !liveIds.has(f.sessionId));
   191→  return sortJobsByStartedAtDesc([...liveJobs, ...extras]);
   192→}
   193→
   194→function send(ws: WebSocket, msg: ServerMessage): void {
   195→  if (ws.readyState === WebSocket.OPEN) {
   196→    ws.send(JSON.stringify(msg));
   197→  }
   198→}
   199→
   200→function broadcast(clients: Set<WebSocket>, msg: ServerMessage): void {
   201→  const payload = JSON.stringify(msg);
   202→  for (const ws of clients) {
