   207→// ---------------------------------------------------------------------------
   208→// Per-session log stream handler
   209→// ---------------------------------------------------------------------------
   210→
   211→/** Start streaming logs for sessionId to ws. Returns a cancel function. */
   212→async function startLogStream(
   213→  ws: WebSocket,
   214→  sessionId: string,
   215→  namespace: string,
   216→  cachedJobs: Job[]
   217→): Promise<() => void> {
   218→  try {
   219→    const podName = await findPodForSession(sessionId, namespace);
   220→    if (!podName) {
   221→      // Try fixture fallback for local dev
   222→      const fixture = findFixture(sessionId);
   223→      if (fixture) {
   224→        console.log(`[ws] Streaming fixture for ${sessionId}: ${fixture}`);
   225→        send(ws, { type: "fixture-start", ts: Date.now(), sessionId });
   226→        const lines = readFileSync(fixture, "utf-8").split("\n").filter((l) => l.trim());
   227→        const events: unknown[] = [];
   228→        let cancelled = false;
   229→        let paused = false;
   230→        let speed = 1;
   231→        let lineIndex = 0;
   232→        let timer: ReturnType<typeof setTimeout> | null = null;
   233→
   234→        const baseDelay = 200;
   235→
   236→        const streamNext = (): void => {
   237→          if (cancelled) return;
   238→          if (paused) return; // will be resumed by set-speed message
   239→          if (lineIndex >= lines.length) {
   240→            const verdict = detectVerdict(events as Parameters<typeof detectVerdict>[0]);
   241→            if (verdict) {
   242→              send(ws, { type: "verdict", ts: Date.now(), sessionId, result: verdict.pass ? "PASS" : "FAIL" });
   243→            }
   244→            send(ws, { type: "stream-end", ts: Date.now(), sessionId, reason: "completed" });
   245→            return;
   246→          }
   247→          const line = lines[lineIndex++]!;
   248→          send(ws, { type: "log-line", ts: Date.now(), sessionId, line });
   249→          const ev = parseJsonlLine(line);
   250→          if (ev) events.push(ev);
   251→          // Non-JSON lines (entrypoint setup) stream instantly, JSON events get delayed
   252→          const delay = ev ? baseDelay / speed : 0;
   253→          timer = setTimeout(streamNext, delay);
   254→        };
   255→
   256→        // Listen for speed/pause control messages
   257→        const onSpeedMessage = (data: unknown): void => {
