      const msg = await waitForType<{ type: string; jobs: Job[] }>(nextMsg, "jobs-updated");
      expect(msg.jobs[0]?.status).toBe("succeeded");
      expect(msg.jobs[0]?.completedAt).toBe("2026-03-15T11:00:00Z");
    } finally {
      ws.close();
    }
  });

