      expect(s1.jobs[0]?.status).toBe("pending");

      capture.watchCb!([makeJob({ status: "running" })]);
      const s2 = await waitForType<{ type: string; jobs: Job[] }>(nextMsg, "jobs-updated");
      expect(s2.jobs[0]?.status).toBe("running");

