    sessionId: "issue-963-step1-loki",
    name: "agent-issue-963-step1-loki",
    issueNumber: 963,
    agent: "loki",
    step: 1,
    status: "pending",
    startedAt: "2026-03-15T10:00:00Z",
    completedAt: null,
    podName: null,
