     1→/**
     2→ * Issue #984 — Session list sort: newest (and pending) first
     3→ *
     4→ * Tests the useJobs hook's sort behaviour directly, without mounting React.
     5→ * We test the sort comparator extracted from the hook — the same logic that
     6→ * runs on every jobs-snapshot / jobs-updated message.
     7→ */
     8→
     9→import { describe, it, expect } from "vitest";
    10→
    11→// ---------------------------------------------------------------------------
    12→// Mirror the sort comparator from useJobs.ts so tests stay in sync
    13→// ---------------------------------------------------------------------------
    14→
    15→interface ParsedJob {
    16→  sessionId: string;
    17→  startTime: number | null;
    18→}
    19→
    20→function sortJobs(jobs: ParsedJob[]): ParsedJob[] {
    21→  return [...jobs].sort((a, b) => {
    22→    const aTime = a.startTime ?? Number.MAX_SAFE_INTEGER;
    23→    const bTime = b.startTime ?? Number.MAX_SAFE_INTEGER;
    24→    return bTime - aTime;
    25→  });
    26→}
    27→
    28→function makeJob(sessionId: string, startedAt: string | null): ParsedJob {
    29→  return {
    30→    sessionId,
    31→    startTime: startedAt ? new Date(startedAt).getTime() : null,
    32→  };
    33→}
    34→
    35→// ---------------------------------------------------------------------------
    36→// Descending order (newest first)
    37→// ---------------------------------------------------------------------------
    38→
    39→describe("useJobs sort — descending by startTime", () => {
    40→  it("single job is returned unchanged", () => {
    41→    const result = sortJobs([makeJob("a", "2026-03-15T10:00:00Z")]);
    42→    expect(result[0]?.sessionId).toBe("a");
    43→  });
    44→
    45→  it("two jobs: newer appears first", () => {
    46→    const result = sortJobs([
